def gcd(a, b):
    if b == 0:
        return a
    else:
        return gcd(b, a % b)

def f(p):
    n = len(p)
    g = [0] * (n + 1)
    s = set()
    for i in range(1, n + 1):
        g[i] = gcd(g[i - 1], p[i - 1])
        s.add(g[i])
    return len(s)

def fmax(n):
    return max(f(p) for p in permutations(range(1, n + 1)))

def count_permutations(n):
    return sum(1 for p in permutations(range(1, n + 1)) if f(p) == fmax(n))

def main():
    n = int(input())
    print(count_permutations(n) % (10**9 + 7))

if __name__ == "__main__":
    main()
